code = """import json

# Load NYSE non-ETF stock data
stockinfo_path = locals().get('var_functions.query_db:0')
if isinstance(stockinfo_path, str) and stockinfo_path.endswith('.json'):
    with open(stockinfo_path, 'r') as f:
        stockinfo_data = json.load(f)
else:
    stockinfo_data = locals().get('var_functions.query_db:0', [])

# Create symbol to name mapping
symbol_to_name = {stock['Symbol']: stock['Company Description'] for stock in stockinfo_data}
all_symbols = list(symbol_to_name.keys())

# Build UNION ALL query carefully
union_parts = []
for symbol in all_symbols:
    # Escape quotes if any
    esc_symbol = symbol.replace('"', '""')
    part = f"SELECT '{esc_symbol}' as symbol, COUNT(*) as total_days, SUM(CASE WHEN Close > Open THEN 1 ELSE 0 END) as up_days, SUM(CASE WHEN Close < Open THEN 1 ELSE 0 END) as down_days FROM \"{esc_symbol}\" WHERE Date >= '2017-01-01' AND Date <= '2017-12-31'"
    union_parts.append(part)

full_union = ' UNION ALL '.join(union_parts)
final_sql = f"SELECT t.symbol, t.up_days, t.down_days, (t.up_days - t.down_days) as diff FROM ({full_union}) t WHERE t.up_days > t.down_days AND t.total_days > 0 ORDER BY diff DESC LIMIT 5"

result = {
    'stock_count': len(all_symbols),
    'query_preview': final_sql[:200] + '...' if len(final_sql) > 200 else final_sql,
    'query_size': len(final_sql)
}

print('__RESULT__:')
print(json.dumps(result))"""

